// CloudFront Function: redirect /old-path to /new-path (runs at every PoP)
function handler(event) {
  var request = event.request;
  if (request.uri === '/old-path') {
    return {
      statusCode: 301,
      statusDescription: 'Moved Permanently',
      headers: {
        'location': { value: '/new-path' }
      }
    };
  }
  return request;
}

# Create a latency-based routing record that routes users
# to the closest AWS Region based on PoP measurements
aws route53 change-resource-record-sets \
  --hosted-zone-id Z3M3LMPEXAMPLE \
  --change-batch '{
    "Changes": [{
      "Action": "CREATE",
      "ResourceRecordSet": {
        "Name": "api.example.com",
        "Type": "A",
        "Region": "us-east-1",
        "SetIdentifier": "us-east-1",
        "AliasTarget": {
          "DNSName": "my-alb.us-east-1.elb.amazonaws.com",
          "EvaluateTargetHealth": true,
          "HostedZoneId": "Z35SXDOTRQ7X7K"
        }
      }
    }]
  }'

# Enable Real-Time Logs to see per-PoP data (includes x-edge-location field)
aws cloudfront create-realtime-log-config \
  --end-points '[{
    "StreamType": "Kinesis",
    "KinesisStreamConfig": {
      "RoleARN": "arn:aws:iam::123456789012:role/CloudFront-RT-Logs",
      "StreamARN": "arn:aws:kinesis:us-east-1:123456789012:stream/cf-rt-logs"
    }
  }]' \
  --fields 'timestamp' 'x-edge-location' 'sc-bytes' 'cs-method' \
           'x-edge-result-type' 'x-host-header' 'sc-status' \
  --name 'cf-per-pop-logging' \
  --sampling-rate 5

# Configure origin failover with primary and secondary origins
aws cloudfront create-distribution --distribution-config '{
  "Origins": {
    "Quantity": 2,
    "Items": [
      {"Id": "primary-s3", "DomainName": "primary.s3.amazonaws.com"},
      {"Id": "secondary-s3", "DomainName": "secondary.s3.amazonaws.com"}
    ]
  },
  "OriginGroups": {
    "Quantity": 1,
    "Items": [{
      "Id": "failover-group",
      "FailoverCriteria": {
        "StatusCodes": {"Quantity": 2, "Items": [500, 502]}
      },
      "Members": {
        "Quantity": 2,
        "Items": [
          {"OriginId": "primary-s3"},
          {"OriginId": "secondary-s3"}
        ]
      }
    }]
  }
}'

resource "aws_cloudfront_distribution" "website" {
  enabled             = true
  default_root_object = "index.html"
  price_class         = "PriceClass_100"  # US + Europe PoPs only

  origin {
    domain_name              = aws_s3_bucket.website.bucket_regional_domain_name
    origin_id                = "s3-website"
    origin_access_control_id = aws_cloudfront_origin_access_control.main.id
  }

  default_cache_behavior {
    allowed_methods        = ["GET", "HEAD"]
    cached_methods         = ["GET", "HEAD"]
    target_origin_id       = "s3-website"
    viewer_protocol_policy = "redirect-to-https"
    cache_policy_id        = data.aws_cloudfront_cache_policy.optimized.id
  }

  logging_config {
    include_cookies = false
    bucket          = aws_s3_bucket.logs.bucket_domain_name
    prefix          = "cf/"
  }

  restrictions {
    geo_restriction { restriction_type = "none" }
  }

  viewer_certificate {
    acm_certificate_arn      = aws_acm_certificate.main.arn
    ssl_support_method       = "sni-only"
    minimum_protocol_version = "TLSv1.2_2021"
  }
}
